---

## Current Issues

### 1. Missing Body Parsing Middleware
No `express.json()` or `express.urlencoded()` middleware is configured. Any POST/PUT routes added later will silently fail to parse request bodies.

### 2. No Input Validation
The `/users` endpoint (and any future routes) have no query parameter validation — opening the door to unexpected behavior or injection if a database is added later.

### 3. No Rate Limiting
The API is wide open to abuse/DoS without any rate limiting.

### 4. No Security Headers
Express exposes the `X-Powered-By: Express` header by default, leaking implementation details.

### 5. No Error Handling Middleware
Unhandled errors will cause Express to respond with stack traces (in development) or crash silently.

### 6. No Request Logging
No way to detect or audit suspicious activity.

### 7. Hardcoded Port
`3000` is hardcoded rather than read from the environment, which is both inflexible and a minor ops concern.

---

## Suggested Improvements

```js
const express = require('express');
const app = express();

// --- Security: remove X-Powered-By header ---
app.disable('x-powered-by');

// --- Middleware: parse JSON/urlencoded bodies ---
app.use(express.json({ limit: '10kb' }));       // cap body size to prevent DoS
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Optional but recommended: helmet for security headers ---
// const helmet = require('helmet');
// app.use(helmet());

// --- Optional but recommended: rate limiting ---
// const rateLimit = require('express-rate-limit');
// app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }));

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Input validation: reject unexpected query params or sanitize them
  const allowedParams = ['page', 'limit'];
  const unknownParams = Object.keys(req.query).filter(k => !allowedParams.includes(k));
  if (unknownParams.length > 0) {
    return res.status(400).json({ error: `Unknown query parameters: ${unknownParams.join(', ')}` });
  }

  const page = parseInt(req.query.page, 10) || 1;
  const limit = parseInt(req.query.limit, 10) || 10;

  if (page < 1 || limit < 1 || limit > 100) {
    return res.status(400).json({ error: 'Invalid pagination parameters' });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler ---
app.use((err, req, res, next) => {
  console.error(err.stack);
  const status = err.status || err.statusCode || 500;
  const message = process.env.NODE_ENV === 'production'
    ? 'Internal server error'   // never leak stack traces in prod
    : err.message;
  res.status(status).json({ error: message });
});

// --- Start server ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

